public class Solution { public string Encode(IList<string> strs) { StringBuilder res = new StringBuilder(); List<int> sizes = new List<int>(); foreach (string str in strs) { sizes.Add(str.Length); } foreach (int size in sizes) { res.Append(size).Append(','); } res.Append('#'); foreach (string str in strs) { res.Append(str); } return res.ToString(); } public List<string> Decode(string s) { List<string> decode = new List<string>(); List<int> size = new List<int>(); int i = 0; while (s[i] != '#') { StringBuilder res = new StringBuilder(); while (s[i] != ',') { res.Append(s[i]); i++; } size.Add(Convert.ToInt32(res.ToString())); i++; } i++; foreach (int z in size) { decode.Add(s.Substring(i, z)); i += z; } return decode; } }